fn lex(input: &[char]) -> Vec<String> {
    let mut result = Vec::new();
    let mut iter = input.iter().peekable();

    while let Some(c) = iter.next() {
        if c.is_alphabetic() {
            let mut token = String::from(*c);
            while let Some(next) = iter.peek() {
                if next.is_alphabetic() {
                    token.push(**next);
                    iter.next();
                } else {
                    break;
                }
            }
            result.push(token);
        }
    }

    result
}
